  2	import * as React from 'react';
  3	import { Tooltip } from '@patternfly/react-core';
  4	import { createSvgIdUrl, useHover } from '@patternfly/react-topology';
  5	import cx from 'classnames';
  6	import * as _ from 'lodash';
  7	import { Link } from 'react-router-dom-v5-compat';
  8	
  9	import {
 10	  createStepStatus,
 11	  StepStatus,
 12	  TaskStatus,
 13	} from './pipeline-step-utils';
 14	import { PipelineVisualizationStepList } from './PipelineVisualizationStepList';
 15	import { StatusIcon } from './StatusIcon';
 16	
 17	import './PipelineVisualizationTask.scss';
 18	import { getRunStatusColor } from '../utils/pipeline-augment';
 19	import { t } from '../utils/common-utils';
 20	import {
 21	  ComputedStatus,
 22	  PipelineTaskRef,
 23	  TaskKind,
 24	  TektonTaskSpec,
 25	  WhenExpression,
 26	} from '../../types';
 27	import { PipelineRunModel } from '../../models';
 28	import { truncateMiddle } from '../pipeline-topology/truncate-middle';
 29	import SvgDropShadowFilter from '../pipeline-topology/SvgDropShadowFilter';
 30	import { WHEN_EXPRESSSION_DIAMOND_SIZE } from './const';
 31	import WhenExpressionDecorator from '../pipeline-topology/WhenExpressionDecorator';
 32	import { resourcePathFromModel } from '../utils/utils';
 33	import '../styles/common.scss';
 34	
 35	type PipelineVisualizationTask = {
 36	  name?: string;
 37	  taskSpec?: TektonTaskSpec;
 38	  taskRef?: PipelineTaskRef;
 39	  runAfter?: string[];
 40	  when?: WhenExpression[];
 41	  status?: TaskStatus;
 42	};
 43	interface TaskProps {
 44	  pipelineRunName?: string;
 45	  name: string;
 46	  loaded?: boolean;
 47	  task?: {
 48	    data: TaskKind;
 49	  };
 50	  status: TaskStatus;
 51	  namespace: string;
 52	  isPipelineRun: boolean;
 53	  disableVisualizationTooltip?: boolean;
 54	  selected?: boolean;
 55	  width: number;
 56	  height: number;
 57	  isFinallyTask?: boolean;
 58	  pipelineTask: PipelineVisualizationTask;
 59	}
 60	
 61	interface PipelineVisualizationTaskProp {
 62	  pipelineRunName?: string;
 63	  namespace: string;
 64	  task: PipelineVisualizationTask;
 65	  taskRun?: string;
 66	  pipelineRunStatus?: string;
 67	  disableTooltip?: boolean;
 68	  selected?: boolean;
 69	  isSkipped?: boolean;
 70	  width: number;
 71	  height: number;
 72	  isFinallyTask?: boolean;
 73	}
 74	
 75	const FILTER_ID = 'SvgTaskDropShadowFilterId';
 76	
 77	export const PipelineVisualizationTask: React.FC<
 78	  PipelineVisualizationTaskProp
 79	> = ({
 80	  pipelineRunName,
 81	  task,
 82	  namespace,
 83	  pipelineRunStatus,
 84	  disableTooltip,
 85	  selected,
 86	  isSkipped,
 87	  width,
 88	  height,
 89	  isFinallyTask,
 90	}) => {
 91	  const taskStatus = task.status || {
 92	    duration: '',
 93	    reason: ComputedStatus.Idle,
 94	  };
 95	  if (
 96	    pipelineRunStatus === ComputedStatus.Failed ||
 97	    pipelineRunStatus === ComputedStatus.Cancelled
 98	  ) {
 99	    if (
100	      task.status?.reason === ComputedStatus.Idle ||
101	      task.status?.reason === ComputedStatus.Pending
102	    ) {
103	      taskStatus.reason = ComputedStatus.Cancelled;
104	    }
105	  }
106	  if (isSkipped) {
107	    taskStatus.reason = ComputedStatus.Skipped;
108	  }
109	
110	  const taskComponent = (
111	    <TaskComponent
112	      pipelineRunName={pipelineRunName}
113	      name={task.name || ''}
114	      task={task.taskSpec && { data: { spec: task.taskSpec } }}
115	      namespace={namespace}
116	      status={taskStatus}
117	      isPipelineRun={!!pipelineRunStatus}
118	      disableVisualizationTooltip={disableTooltip}
119	      selected={selected}
120	      width={width}
121	      height={height}
122	      isFinallyTask={isFinallyTask}
123	      pipelineTask={task}
124	    />
125	  );
126	
127	  if (disableTooltip || task.taskSpec) {
128	    return taskComponent;
129	  }
130	
131	  return taskComponent;
132	};
133	const TaskComponent: React.FC<TaskProps> = ({
134	  pipelineRunName,
135	  namespace,
136	  task,
137	  status,
138	  name,
139	  isPipelineRun,
140	  disableVisualizationTooltip,
141	  selected,
142	  width,
143	  height,
144	  isFinallyTask,
145	  pipelineTask,
146	}) => {
147	  const stepList = task?.data?.spec?.steps || [];
148	  const stepStatusList: StepStatus[] = stepList.map((step) =>
149	    createStepStatus(step, status),
150	  );
151	  const showStatusState: boolean = isPipelineRun && !!status && !!status.reason;
152	  const visualName = name || _.get(task, ['metadata', 'name'], '');
153	  const nameRef = React.useRef();
154	  const pillRef = React.useRef();
155	  const path = pipelineRunName
156	    ? `${resourcePathFromModel(
157	        PipelineRunModel,
158	        pipelineRunName,
159	        namespace,
160	      )}/logs/${name}`
161	    : undefined;
162	  const enableLogLink =
163	    status?.reason !== ComputedStatus.Idle &&
164	    status?.reason !== ComputedStatus.Pending &&
165	    status?.reason !== ComputedStatus.Cancelled &&
166	    !!path;
167	  const hasWhenExpression = pipelineTask?.when?.length > 0;
168	  const hasRunAfter = pipelineTask?.runAfter?.length > 0;
169	  const taskStatusColor = status
170	    ? getRunStatusColor(status.reason, t).pftoken.value
171	    : getRunStatusColor(ComputedStatus.Cancelled, t).pftoken.value;
172	
173	  const [hover, hoverRef] = useHover();
174	  const truncatedVisualName = React.useMemo(
175	    () =>
176	      truncateMiddle(visualName, {
177	        length: showStatusState ? 11 : 14,
178	        truncateEnd: true,
179	      }),
180	    [visualName, showStatusState],
181	  );
182	
183	  const renderVisualName = (
184	    <text
185	      ref={nameRef}
186	      x={showStatusState ? 30 : width / 2}
187	      y={height / 2 + 1}
188	      className={cx('odc-pipeline-vis-task-text', {
189	        'is-text-center': !isPipelineRun,
190	        'is-linked': enableLogLink,
191	      })}
192	    >
193	      {truncatedVisualName}
194	    </text>
195	  );
196	
197	  let taskPill = (
198	    <g ref={hoverRef}>
199	      <SvgDropShadowFilter dy={1} id={FILTER_ID} />
200	      <rect
201	        filter={hover ? createSvgIdUrl(FILTER_ID) : ''}
202	        width={width}
203	        height={height}
204	        rx={15}
205	        className={cx('odc-pipeline-vis-task', {
206	          'is-selected': selected,
207	          'is-linked': enableLogLink,
208	        })}
209	      />
210	      {visualName !== truncatedVisualName && disableVisualizationTooltip ? (
211	        <Tooltip triggerRef={nameRef} content={visualName}>
212	          {renderVisualName}
213	        </Tooltip>
214	      ) : (
215	        renderVisualName
216	      )}
217	
218	      {showStatusState && (
219	        <>
220	          <svg
221	            width={30}
222	            height={30}
223	            viewBox="-5 -4 20 20"
224	            style={{
225	              color: taskStatusColor,
226	            }}
227	          >
228	            <g
229	              className={cx({
230	                'pipelines-console-plugin__spin odc-pipeline-vis-task--icon-spin':
231	                  status.reason === ComputedStatus.Running,
232	                'odc-pipeline-vis-task--icon-stop':
233	                  status.reason !== ComputedStatus.Running,
234	              })}
235	            >
236	              <StatusIcon status={status.reason} disableSpin />
237	            </g>
238	          </svg>
239	          <SvgTaskStatus
240	            steps={stepStatusList}
241	            x={30}
242	            y={23}
243	            width={width / 2 + 15}
244	          />
245	        </>
246	      )}
247	    </g>
248	  );
249	
250	  if (!disableVisualizationTooltip) {
251	    taskPill = (
252	      <>
253	        <Tooltip
254	          triggerRef={pillRef}
255	          position="bottom"
256	          enableFlip={false}
257	          content={
258	            <PipelineVisualizationStepList
259	              isSpecOverview={!isPipelineRun}
260	              taskName={visualName}
261	              steps={stepStatusList}
262	              isFinallyTask={isFinallyTask}
263	            />
264	          }
265	        >
266	          <g ref={pillRef}>{taskPill}</g>
267	        </Tooltip>
268	      </>
269	    );
270	  }
271	
272	  const taskNode = (
273	    <>
274	      {hasWhenExpression && (
275	        <WhenExpressionDecorator
276	          width={WHEN_EXPRESSSION_DIAMOND_SIZE}
277	          height={WHEN_EXPRESSSION_DIAMOND_SIZE}
278	          appendLine={!hasRunAfter && !isFinallyTask}
279	          isPipelineRun={isPipelineRun}
280	          status={status.reason}
281	          enableTooltip
282	          leftOffset={disableVisualizationTooltip && !isFinallyTask ? 3 : 2}
283	          isFinallyTask={isFinallyTask}
284	        />
285	      )}
286	      {taskPill}
287	    </>
288	  );
289	  return enableLogLink ? (
290	    <Link to={path}>
291	      <g data-test={`task ${visualName}`}>{taskNode}</g>
292	    </Link>
293	  ) : (
294	    taskNode
295	  );
296	};
297	
298	interface SvgTaskStatusProps {
299	  steps: StepStatus[];
300	  x: number;
301	  y: number;
302	  width: number;
303	}
304	
305	const SvgTaskStatus: React.FC<SvgTaskStatusProps> = ({
306	  steps,
307	  x,
308	  y,
309	  width,
310	}) => {
311	  if (steps.length === 0) {
312	    return null;
313	  }
314	  const stepWidth = width / steps.length;
315	  const gap = 2;
316	  return (
317	    <g>
318	      {steps.map((step, index) => {
319	        return (
320	          <rect
321	            key={step.name}
322	            x={x + stepWidth * index}
323	            y={y}
324	            width={stepWidth - gap}
325	            height={2}
326	            fill={getRunStatusColor(step.status, t).pftoken.value}
327	          />
328	        );
329	      })}
330	    </g>
331	  );
332	};

